@startuml
class Ginasio {
  - nome: String
  - quadra: List<Quadra>
}

abstract class Pessoa {
  # nome: String
}

class Quadra {
  - numero: Int
  - aluguel: Aluguel
  - ginasio: Ginasio
}

class Clients {
  - id: Int
  - nome: String
  - locaçao: List<Aluguel>
}

class Aluguel {
  - cliente: Client
  - tempo: Int
  - quadra: Quadra
}

Ginasio *-- Quadra
Pessoa <|-- Quadra
Pessoa <|-- Clients
Pessoa <|-- Aluguel
Clients "1" -right-* "0..*" Aluguel
Quadra "1..*" -right-o "1" Aluguel
@enduml
